import React, { useEffect } from "react";
import axios from "axios";
import { startTracking, getData } from "./tracker";

function LetterGame({ onNext }) {
  useEffect(() => {
    startTracking();
  }, []);

  const finishGame = async () => {
    const data = getData();

    try {
      await axios.post("http://localhost:5000/save", {
        studentId: "child_01",
        activity: "letter_matching",
        ...data,
      });
    } catch (err) {
      console.error("LetterGame save failed:", err);
      alert("Progress could not be saved to the server. Continuing anyway.");
    }

    if (onNext) onNext();
  };

  const style = {
    textAlign: "center",
    backgroundColor: "#FFE4E1",
    height: "100vh",
    paddingTop: "50px",
  };

  return (
    <div style={style}>
      <h1>Match Letters 🎉</h1>
      <h2>A → 🍎</h2>
      <h2>B → 🐻</h2>

      <button onClick={finishGame} style={{ fontSize: "20px" }}>
        Next ➡️
      </button>
    </div>
  );
}

export default LetterGame;
